import React, { useState } from "react";
import "./IndividualAnalysis.css";

function IndividualAnalysis({ 
  customerData = {}, 
  onInputChange, 
  onAnalyze, 
  onReset,
  loading, 
  results
}) {
  const [activeTab, setActiveTab] = useState("core");

  const BENCHMARK_PROFILE = {
    'Tenure (Months)': 9, 'Cashback Amount (₹)': 12000, 'Days Since Last Order': 5,
    'Satisfaction Score': 4, 'Warehouse Distance (km)': 10,
  };

  const handleChange = (e) => {
    const { name, value, type } = e.target;
    const processedValue = type === "number" ? parseFloat(value) || 0 : value;
    onInputChange({ ...customerData, [name]: processedValue });
  };

  const handleNumberChange = (name, value) => {
    if (value === "" || value === null || value === undefined) {
      onInputChange({ ...customerData, [name]: "" });
    } else {
      const numValue = parseFloat(value);
      if (!isNaN(numValue)) {
        onInputChange({ ...customerData, [name]: numValue });
      }
    }
  };

  const handleRangeChange = (name, value) => {
    onInputChange({ ...customerData, [name]: parseFloat(value) });
  };

  const toggleComplaint = () => {
    onInputChange({ 
      ...customerData, 
      Complain: customerData.Complain === 1 ? 0 : 1 
    });
  };

  const renderField = (label, name, type = "number", options = null, step = 1, helpText = "") => {
    if (name === "SatisfactionScore") {
      return (
        <div className="field-container">
          <div className="field-header">
            <label htmlFor={name} className="field-label">{label}</label>
            {helpText && <span className="field-help" title={helpText}>ℹ️</span>}
          </div>
          <div className="range-slider-container">
            <input
              id={name}
              type="range"
              name={name}
              min="1"
              max="5"
              step="1"
              value={customerData[name] || 1}
              onChange={(e) => handleRangeChange(name, e.target.value)}
              className="range-slider"
            />
            <div className="range-labels">
              <span className="range-label">1</span>
              <span className="range-label">2</span>
              <span className="range-label">3</span>
              <span className="range-label">4</span>
              <span className="range-label">5</span>
            </div>
            <div className="range-value-display">
              <span className="range-current-value">{customerData[name] || 1}</span>
              <span className="range-max-value">/5</span>
            </div>
          </div>
        </div>
      );
    }

    if (name === "Complain") {
      return (
        <div className="field-container">
          <div className="field-header">
            <label className="field-label">{label}</label>
            {helpText && <span className="field-help" title={helpText}>ℹ️</span>}
          </div>
          <div className="toggle-button-container">
            <button
              type="button"
              className={`simple-toggle-btn ${customerData.Complain === 1 ? 'active' : ''}`}
              onClick={toggleComplaint}
            >
              <span className="toggle-track">
                <span className="toggle-thumb"></span>
              </span>
              <span className="toggle-label">
                {customerData.Complain === 1 ? 'Complaint Filed' : 'No Complaint'}
              </span>
            </button>
          </div>
        </div>
      );
    }

    return (
      <div className="field-container">
        <div className="field-header">
          <label htmlFor={name} className="field-label">{label}</label>
          {helpText && <span className="field-help" title={helpText}>ℹ️</span>}
        </div>
        {options ? (
          <select 
            id={name}
            name={name} 
            value={customerData[name] || ""}
            onChange={handleChange}
            className="form-select"
          >
            <option value="">Select an option</option>
            {options.map((opt, i) => (
              <option key={i} value={opt}>
                {opt}
              </option>
            ))}
          </select>
        ) : type === "number" ? (
          <input 
            id={name}
            type="number"
            name={name} 
            value={customerData[name] ?? ""}
            onChange={(e) => handleNumberChange(name, e.target.value)}
            step={step}
            min="0"
            className="form-input number-input-simple"
            placeholder="0"
          />
        ) : (
          <input 
            id={name}
            type={type} 
            name={name} 
            value={customerData[name] || ""}
            onChange={handleChange}
            className="form-input"
            placeholder="Enter value"
          />
        )}
      </div>
    );
  };

  const GaugeChart = ({ probability }) => {
    const percentage = probability * 100;
    let level, color;
    
    if (percentage < 30) {
      level = 'LOW';
      color = '#10b981';
    } else if (percentage < 70) {
      level = 'MODERATE';
      color = '#f59e0b';
    } else {
      level = 'HIGH';
      color = '#ef4444';
    }

    return (
      <div className="gauge-container">
        <div className="gauge-title">Churn Risk — {level}</div>
        <div className="gauge">
          <div className="gauge-background">
            <div className="gauge-fill" style={{ 
              transform: `rotate(${percentage * 1.8}deg)`,
              backgroundColor: color 
            }}></div>
          </div>
          <div className="gauge-value">{percentage.toFixed(1)}%</div>
        </div>
        <div className="gauge-labels">
          <span>0%</span>
          <span>50%</span>
          <span>100%</span>
        </div>
      </div>
    );
  };

  const DeviationChart = ({ currentData }) => {
    const directions = {
      'Tenure (Months)': -1, 'Cashback Amount (₹)': -1, 'Days Since Last Order': 1,
      'Satisfaction Score': -1, 'Warehouse Distance (km)': 1,
    };

    const deviations = Object.keys(BENCHMARK_PROFILE).map(feature => {
      const current = currentData[feature] || BENCHMARK_PROFILE[feature];
      const benchmark = BENCHMARK_PROFILE[feature];
      const direction = directions[feature] || 1;
      const deviation = ((current - benchmark) / benchmark) * 100 * direction;
      
      let color = '#34d399'; // Mitigating
      if (deviation > 0) color = '#f97316'; // Risk
      if (deviation > 50) color = '#ef4444'; // Top Risk
      
      return {
        feature,
        deviation,
        color,
        type: deviation > 50 ? 'Top Risk Factor' : deviation > 0 ? 'Risk Factor' : 'Mitigating Factor'
      };
    }).sort((a, b) => a.deviation - b.deviation);

    return (
      <div className="chart-container">
        <h4>Deviation vs Benchmark (Positive = Higher Risk)</h4>
        <div className="deviation-chart">
          {deviations.map((item, index) => (
            <div key={item.feature} className="deviation-bar-container">
              <div className="deviation-label">{item.feature}</div>
              <div className="deviation-bar-wrapper">
                <div 
                  className="deviation-bar"
                  style={{ 
                    width: `${Math.min(Math.abs(item.deviation), 100)}%`,
                    backgroundColor: item.color,
                    marginLeft: item.deviation < 0 ? 'auto' : '0'
                  }}
                ></div>
                <div className="deviation-value">{item.deviation.toFixed(1)}%</div>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const FeatureContributionChart = ({ contributions }) => {
    const topFeatures = contributions.slice(0, 10);
    
    return (
      <div className="chart-container">
        <h4>Top 10 Key Churn Risk Factors</h4>
        <div className="feature-contribution-chart">
          {topFeatures.map((feature, index) => (
            <div key={feature.Feature} className="feature-item">
              <div className="feature-header">
                <span className="feature-rank">#{index + 1}</span>
                <span className="feature-name">{feature.Feature}</span>
                <span className="feature-value">{(feature.Contribution * 100).toFixed(1)}%</span>
              </div>
              <div className="feature-bar">
                <div 
                  className="feature-fill"
                  style={{ width: `${feature.Contribution * 100}%` }}
                ></div>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const ActionPlan = ({ prediction, probability, businessImpact }) => {
    const riskLevel = probability > 0.7 ? "HIGH" : probability > 0.4 ? "MEDIUM" : "LOW";
    
    const getRecommendations = () => {
      if (probability < 0.3) {
        return [
          "Loyalty Reinforcement: Enroll in a tiered loyalty program",
          "Proactive Value Communication: Use non-sales content",
          "Advocacy & Growth: Offer incentives for referrals"
        ];
      } else if (probability < 0.7) {
        return [
          "Timed Intervention: Deploy exclusive discount within 7 days",
          "Friction Removal: Focus on pain points in payments/app",
          "Personalization: Send product recommendations"
        ];
      } else {
        return [
          "Critical 1:1 Outreach: Executive contact within 24 hours",
          "Premium Incentives: Offer free upgrades or premium features",
          "Root Cause Analysis: Analyze last 3 interactions"
        ];
      }
    };

    return (
      <div className="action-plan">
        <h3>🎯 Customer Retention Action Plan</h3>
        
        <div className="quick-actions">
          <button className="action-btn">📧 Send Personalized Offer</button>
          <button className="action-btn">📞 Schedule Support Call</button>
          <button className="action-btn">⭐ Assign VIP Status</button>
        </div>

        <div className="business-impact">
          <h4>💼 Business Impact Summary</h4>
          <div className="impact-grid">
            <div className="impact-item">
              <span className="impact-label">Estimated CLV</span>
              <span className="impact-value">₹{businessImpact.estimated_clv?.toLocaleString()}</span>
            </div>
            <div className="impact-item">
              <span className="impact-label">Potential Loss</span>
              <span className="impact-value">₹{businessImpact.potential_revenue_loss?.toLocaleString()}</span>
            </div>
            <div className="impact-item">
              <span className="impact-label">Retention Budget</span>
              <span className="impact-value">₹{businessImpact.retention_budget?.toLocaleString()}</span>
            </div>
            <div className="impact-item">
              <span className="impact-label">ROI Potential</span>
              <span className="impact-value">{businessImpact.roi_retention?.toFixed(1)}x</span>
            </div>
          </div>
        </div>

        <div className="recommendations">
          <h4>📋 Recommended Actions</h4>
          <div className="recommendations-list">
            {getRecommendations().map((rec, index) => (
              <div key={index} className="recommendation-item">
                <span className="rec-number">{index + 1}</span>
                <span className="rec-text">{rec}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  };

  const renderResults = () => {
    if (!results) return null;

    const probability = results.probability || 0;
    const prediction = results.prediction || false;
    const businessImpact = results.business_impact || {};
    const featureContributions = results.feature_contributions || [];

    const currentProfile = {
      'Tenure (Months)': customerData.Tenure || 0,
      'Cashback Amount (₹)': customerData.CashbackAmount || 0,
      'Days Since Last Order': customerData.DaySinceLastOrder || 0,
      'Satisfaction Score': customerData.SatisfactionScore || 0,
      'Warehouse Distance (km)': customerData.WarehouseToHome || 0,
    };

    const riskLevel = probability > 0.7 ? "high" : probability > 0.4 ? "medium" : "low";
    const topDriver = featureContributions[0]?.Feature || "general behavior";

    return (
      <div className="results-panel">
        <div className="results-header">
          <h3>📊 Analysis Results</h3>
          <div className="results-meta">
            <span className="timestamp">Generated: {new Date().toLocaleTimeString()}</span>
          </div>
        </div>

        {/* Risk Alert */}
        <div className={`risk-alert ${riskLevel}`}>
          <span className="alert-icon">
            {riskLevel === 'high' ? '🚨' : riskLevel === 'medium' ? '⚠️' : '✅'}
          </span>
          <span className="alert-text">
            <strong>{riskLevel.toUpperCase()} RISK ({(probability * 100).toFixed(1)}%)</strong>: 
            Primary risk factor identified as <strong>{topDriver}</strong>.
          </span>
        </div>

        {/* KPI Cards */}
        <div className="kpi-grid">
          <div className="kpi-card">
            <div className="kpi-title">Current Churn Risk</div>
            <div className="kpi-value">{(probability * 100).toFixed(1)}%</div>
          </div>
          <div className="kpi-card">
            <div className="kpi-title">Customer Tenure</div>
            <div className="kpi-value">{customerData.Tenure || 0} mo</div>
          </div>
          <div className="kpi-card">
            <div className="kpi-title">Days Since Last Order</div>
            <div className="kpi-value">{customerData.DaySinceLastOrder || 0} d</div>
          </div>
          <div className="kpi-card">
            <div className="kpi-title">Satisfaction Score</div>
            <div className="kpi-value">{customerData.SatisfactionScore || 0}/5</div>
          </div>
        </div>

        {/* Charts Section */}
        <div className="charts-section">
          <div className="chart-row">
            <div className="chart-item">
              <GaugeChart probability={probability} />
            </div>
            <div className="chart-item">
              <DeviationChart currentData={currentProfile} />
            </div>
          </div>
          
          <div className="chart-row">
            <div className="chart-item full-width">
              <FeatureContributionChart contributions={featureContributions} />
            </div>
          </div>
        </div>

        {/* Action Plan */}
        <ActionPlan 
          prediction={prediction}
          probability={probability}
          businessImpact={businessImpact}
        />

        {/* Export Report */}
        <div className="export-section">
          <button className="export-btn">
            📥 Download Comprehensive Customer Report
          </button>
        </div>
      </div>
    );
  };

  return (
    <div className="individual-analysis">
      <div className="analysis-header">
        <h2>👤 Customer Profile Data Input</h2>
        <p>Enter customer details to predict churn probability and get actionable insights</p>
      </div>

      <div className="content-tabs">
        <button 
          className={`tab-btn ${activeTab === "core" ? "active" : ""}`}
          onClick={() => setActiveTab("core")}
        >
          💰 Core Metrics
        </button>
        <button 
          className={`tab-btn ${activeTab === "logistics" ? "active" : ""}`}
          onClick={() => setActiveTab("logistics")}
        >
          🛠️ Service & Logistics
        </button>
        <button 
          className={`tab-btn ${activeTab === "demographics" ? "active" : ""}`}
          onClick={() => setActiveTab("demographics")}
        >
          🧑 Demographics
        </button>
      </div>

      <div className="content-panel">
        {/* Quick Stats */}
        <div className="quick-stats">
          <div className="stat-card">
            <div className="stat-icon tenure">📅</div>
            <div className="stat-info">
              <span className="stat-value">{customerData.Tenure || 0}</span>
              <span className="stat-label">Months Tenure</span>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon orders">🛒</div>
            <div className="stat-info">
              <span className="stat-value">{customerData.OrderCount || 0}</span>
              <span className="stat-label">Total Orders</span>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon satisfaction">⭐</div>
            <div className="stat-info">
              <span className="stat-value">{customerData.SatisfactionScore || 1}/5</span>
              <span className="stat-label">Satisfaction</span>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon cashback">💰</div>
            <div className="stat-info">
              <span className="stat-value">₹{customerData.CashbackAmount || 0}</span>
              <span className="stat-label">Cashback Amount</span>
            </div>
          </div>
        </div>

        {/* Tab Content */}
        <div className="tab-content-area">
          {activeTab === "core" && (
            <div className="tab-panel active">
              <div className="fields-grid">
                {renderField("Customer Lifetime (Months)", "Tenure", "number", null, 1, "Total months as customer")}
                {renderField("Total Orders", "OrderCount", "number", null, 1, "Lifetime orders placed")}
                {renderField("Total Cashback Earned (₹)", "CashbackAmount", "number", null, 100, "Total cashback earned")}
                {renderField("Days Since Last Order", "DaySinceLastOrder", "number", null, 1, "Recency of last purchase")}
                {renderField("App Time (Hours/month)", "HourSpendOnApp", "number", null, 0.5, "Monthly app engagement hours")}
                {renderField("Perceived Price Increase (%)", "OrderAmountHikeFromlastYear", "number", null, 1, "Year-over-year order value change")}
                {renderField("Coupons Used", "CouponUsed", "number", null, 1, "Total discount coupons redeemed")}
                {renderField("Devices Registered", "NumberOfDeviceRegistered", "number", null, 1, "Number of registered devices")}
              </div>
            </div>
          )}

          {activeTab === "logistics" && (
            <div className="tab-panel active">
              <div className="complaint-simple-container">
                {renderField("Has a Formal Complaint?", "Complain", "select", null, null, "Recent service complaints")}
              </div>
              <div className="fields-grid logistics-fields">
                {renderField("Satisfaction Score (1-5)", "SatisfactionScore", "number", null, 1, "Customer satisfaction rating")}
                {renderField("Warehouse Distance (km)", "WarehouseToHome", "number", null, 1, "Distance to nearest warehouse")}
                {renderField("Delivery Addresses", "NumberOfAddress", "number", null, 1, "Number of saved addresses")}
                {renderField("City Tier", "CityTier", "select", [1, 2, 3], null, "City classification tier")}
                {renderField("Login Device", "PreferredLoginDevice", "select", ["Mobile Phone", "Computer"], null, "Primary access device")}
                {renderField("Payment Mode", "PreferredPaymentMode", "select", [
                  "Debit Card", "Credit Card", "UPI", "E wallet", "Cash on Delivery"
                ], null, "Preferred payment option")}
                {renderField("Order Category", "PreferedOrderCat", "select", [
                  "Laptop & Accessory", "Mobile Phone", "Fashion", "Grocery", 
                  "Books & Stationery", "Footwear", "Sports Equipment", "Others"
                ], null, "Most purchased category")}
              </div>
            </div>
          )}

          {activeTab === "demographics" && (
            <div className="tab-panel active">
              <div className="fields-grid demographics-fields">
                <div className="demographics-row">
                  {renderField("Gender", "Gender", "select", ["Female", "Male", "Other"], null, "Customer gender")}
                  {renderField("Marital Status", "MaritalStatus", "select", ["Single", "Married", "Divorced", "Other"], null, "Relationship status")}
                </div>
              </div>
            </div>
          )}
        </div>

        <div className="action-buttons">
          <button 
            className="btn secondary" 
            onClick={onReset}
            disabled={loading}
          >
            Reset Form
          </button>
          <button 
            className="btn primary" 
            onClick={onAnalyze} 
            disabled={loading}
          >
            {loading ? (
              <>
                <div className="spinner"></div>
                Analyzing...
              </>
            ) : (
              "✨ Analyze Customer Risk Now"
            )}
          </button>
        </div>
      </div>

      {renderResults()}
    </div>
  );
}

export default IndividualAnalysis;
